import{_ as a,o as r,c as e,a3 as l}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"📖 世界书 (Worldbook) 概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/worldbook/index.md","filePath":"user-guide/tools/llm-chat/worldbook/index.md","lastUpdated":1778239080000}'),t={name:"user-guide/tools/llm-chat/worldbook/index.md"};function n(i,o,s,d,h,c){return r(),e("div",null,[...o[0]||(o[0]=[l('<h1 id="📖-世界书-worldbook-概览" tabindex="-1">📖 世界书 (Worldbook) 概览 <a class="header-anchor" href="#📖-世界书-worldbook-概览" aria-label="Permalink to &quot;📖 世界书 (Worldbook) 概览&quot;">​</a></h1><p>世界书 (Worldbook) 是一种<strong>关键词触发的上下文注入机制</strong>，灵感来自 SillyTavern 的 World Info / Lorebook 功能。它允许你预先定义大量背景设定，然后在对话中通过关键词自动匹配并注入相关内容。</p><h2 id="什么是世界书" tabindex="-1">什么是世界书？ <a class="header-anchor" href="#什么是世界书" aria-label="Permalink to &quot;什么是世界书？&quot;">​</a></h2><p>想象你正在写一部奇幻小说——你需要记录大量设定：人物关系、地理环境、魔法体系、历史事件……世界书就是这些设定的数据库。</p><p>与传统的一整段系统提示词不同，世界书采用**“按需注入”**策略：只有当前对话中出现了相关关键词，对应的设定才会被加入上下文。这让你可以在不撑爆 Token 预算的前提下，维护一个庞大的知识库。</p><h2 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h2><ol><li><strong>库管理</strong>: 创建、删除、导入或导出世界书库。</li><li><strong>条目定义</strong>: 在世界书中添加具体的设定条目（Entry），并配置其触发关键词。</li><li><strong>关联激活</strong>: 将世界书关联到特定的 <a href="./../agents/index">Agent</a> 或设为全局生效。</li><li><strong>扫描匹配</strong>: 对话过程中，系统自动扫描消息内容，匹配关键词。</li><li><strong>动态注入</strong>: 匹配成功的条目按照预设的优先级和位置，实时组装进发送给 LLM 的提示词中。</li></ol><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="从零创建" tabindex="-1">从零创建 <a class="header-anchor" href="#从零创建" aria-label="Permalink to &quot;从零创建&quot;">​</a></h3><ol><li>打开 <strong>聊天设置</strong> -&gt; <strong>世界书</strong> -&gt; 点击 <strong>「世界书库管理」</strong>。</li><li>点击 <strong>「新建世界书」</strong>，输入名称即可。</li></ol><h3 id="从-sillytavern-导入" tabindex="-1">从 SillyTavern 导入 <a class="header-anchor" href="#从-sillytavern-导入" aria-label="Permalink to &quot;从 SillyTavern 导入&quot;">​</a></h3><p>系统高度兼容 SillyTavern 格式的 World Info JSON 文件：</p><ol><li>在世界书管理器中点击 <strong>「导入」</strong>。</li><li>选择 <code>.json</code> 角色设定文件，系统会自动解析所有条目、关键词及高级元数据。</li></ol><hr><h3 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h3><ul><li><a href="./entry-management">条目管理与配置</a></li><li><a href="./scanning-strategy">扫描策略与高级控制</a></li></ul>',16)])])}const b=a(t,[["render",n]]);export{u as __pageData,b as default};
